diff --git a/src/signatures.ts b/src/signatures.ts
index de04251..81db694 100644
--- a/src/signatures.ts
+++ b/src/signatures.ts
@@ -1,12 +1,24 @@
 import { sign, verify, type KeyLike } from "node:crypto";

-export type SigningKeys = { rsaPrivateKey: KeyLike; rsaPublicKey: KeyLike };
-export type SignatureEnvelope = { rsa: string };
+export type SigningKeys = {
+  rsaPrivateKey: KeyLike;
+  rsaPublicKey: KeyLike;
+  mlDsaPrivateKey: KeyLike;
+  mlDsaPublicKey: KeyLike;
+};
+export type SignatureEnvelope = { mlDsa: string };

-export function signManifest(payload: Buffer, keys: SigningKeys, _context: string): SignatureEnvelope {
-  return { rsa: sign("sha256", payload, keys.rsaPrivateKey).toString("base64") };
+export function signManifest(payload: Buffer, keys: SigningKeys, context: string): SignatureEnvelope {
+  return {
+    mlDsa: sign(null, payload, { key: keys.mlDsaPrivateKey, context: Buffer.from(context) }).toString("base64"),
+  };
 }

-export function verifyManifest(payload: Buffer, envelope: SignatureEnvelope, keys: SigningKeys, _context: string): boolean {
-  return verify("sha256", payload, keys.rsaPublicKey, Buffer.from(envelope.rsa, "base64"));
+export function verifyManifest(payload: Buffer, envelope: SignatureEnvelope, keys: SigningKeys, context: string): boolean {
+  return verify(
+    null,
+    payload,
+    { key: keys.mlDsaPublicKey, context: Buffer.from(context) },
+    Buffer.from(envelope.mlDsa, "base64"),
+  );
 }

